from __future__ import annotations

from dataclasses import dataclass, replace
from decimal import Decimal, InvalidOperation
from typing import TypeAlias


MoneyInput: TypeAlias = Decimal | int | float | str


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidPriceError(ShoppingCartError):
    """Raised when a price is negative or invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item is not present in the cart."""


class ProductPriceMismatchError(ShoppingCartError):
    """Raised when adding an existing product with a different unit price."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def total_price(self) -> Decimal:
        """Return the total price for this cart item."""
        return self.unit_price * self.quantity


@dataclass(frozen=True, slots=True)
class CartItemDetails:
    """Represents a read-only view of a cart item and its calculated total."""

    product_name: str
    unit_price: Decimal
    quantity: int
    total_price: Decimal


class ShoppingCart:
    """Manage shopping cart items, discounts, and totals."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._percentage_discount: Decimal = Decimal("0")
        self._flat_discount: Decimal = Decimal("0")

    def add_item(
        self,
        product_name: str,
        unit_price: MoneyInput,
        quantity: int = 1,
    ) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_name = self._normalize_product_name(product_name)
        normalized_price = self._normalize_money(unit_price, field_name="unit_price")
        self._validate_positive_price(normalized_price)
        self._validate_positive_quantity(quantity)

        existing_item = self._items.get(normalized_name)
        if existing_item is None:
            self._items[normalized_name] = CartItem(
                product_name=normalized_name,
                unit_price=normalized_price,
                quantity=quantity,
            )
            return

        if existing_item.unit_price != normalized_price:
            raise ProductPriceMismatchError(
                f"Product '{normalized_name}' already exists with unit price "
                f"{existing_item.unit_price}, not {normalized_price}."
            )

        self._items[normalized_name] = replace(
            existing_item,
            quantity=existing_item.quantity + quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_name = self._normalize_product_name(product_name)
        self._get_existing_item(normalized_name)
        del self._items[normalized_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing item."""
        normalized_name = self._normalize_product_name(product_name)
        self._validate_positive_quantity(quantity)

        existing_item = self._get_existing_item(normalized_name)
        self._items[normalized_name] = replace(existing_item, quantity=quantity)

    def calculate_subtotal(self) -> Decimal:
        """Calculate the cart subtotal before discounts."""
        return sum(
            (item.total_price for item in self._items.values()),
            Decimal("0"),
        )

    def apply_percentage_discount(self, percentage: MoneyInput) -> None:
        """Apply a percentage discount to the cart total."""
        normalized_percentage = self._normalize_money(
            percentage,
            field_name="percentage_discount",
        )

        if normalized_percentage < Decimal("0") or normalized_percentage > Decimal("100"):
            raise InvalidDiscountError(
                "Percentage discount must be between 0 and 100 inclusive."
            )

        self._percentage_discount = normalized_percentage

    def apply_flat_discount(self, amount: MoneyInput) -> None:
        """Apply a flat discount to the cart total."""
        normalized_amount = self._normalize_money(amount, field_name="flat_discount")

        if normalized_amount < Decimal("0"):
            raise InvalidDiscountError("Flat discount cannot be negative.")

        self._flat_discount = normalized_amount

    def calculate_total(self) -> Decimal:
        """Calculate the final cart total after discounts."""
        subtotal = self.calculate_subtotal()
        percentage_discount_amount = subtotal * self._percentage_discount / Decimal("100")
        discounted_total = subtotal - percentage_discount_amount - self._flat_discount

        return max(discounted_total, Decimal("0"))

    def list_items(self) -> list[CartItemDetails]:
        """Return all cart items with their details."""
        return [
            CartItemDetails(
                product_name=item.product_name,
                unit_price=item.unit_price,
                quantity=item.quantity,
                total_price=item.total_price,
            )
            for item in self._items.values()
        ]

    def clear(self) -> None:
        """Remove all items and reset discounts."""
        self._items.clear()
        self._percentage_discount = Decimal("0")
        self._flat_discount = Decimal("0")

    def _get_existing_item(self, product_name: str) -> CartItem:
        item = self._items.get(product_name)
        if item is None:
            raise ItemNotFoundError(f"Product '{product_name}' is not in the cart.")
        return item

    @staticmethod
    def _normalize_product_name(product_name: str) -> str:
        if not isinstance(product_name, str):
            raise InvalidProductNameError("Product name must be a string.")

        normalized_name = product_name.strip()
        if not normalized_name:
            raise InvalidProductNameError("Product name cannot be empty.")

        return normalized_name

    @staticmethod
    def _normalize_money(value: MoneyInput, *, field_name: str) -> Decimal:
        try:
            normalized_value = Decimal(str(value))
        except (InvalidOperation, ValueError) as error:
            raise InvalidPriceError(f"{field_name} must be a valid number.") from error

        if not normalized_value.is_finite():
            raise InvalidPriceError(f"{field_name} must be finite.")

        return normalized_value

    @staticmethod
    def _validate_positive_price(price: Decimal) -> None:
        if price <= Decimal("0"):
            raise InvalidPriceError("Unit price must be greater than zero.")

    @staticmethod
    def _validate_positive_quantity(quantity: int) -> None:
        if not isinstance(quantity, int):
            raise InvalidQuantityError("Quantity must be an integer.")

        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")
